// Normaliza para comparar (minúsculas, sin acentos).
export function geoNorm(s) {
  return String(s == null ? '' : s).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
}

// Entrada GEO del país (por nombre de stores.country / storeCountry) o null.
export function geoForCountry(country) {
  if (GEO[country]) return GEO[country];
  const n = geoNorm(country);
  for (const k of Object.keys(GEO)) { if (geoNorm(k) === n) return GEO[k]; }
  return null;
}

// Ciudades (nivel 2) del nivel-1 elegido. Match normalizado; sin match exacto
// devuelve TODAS las del país (buscable igual).
export function level2For(geo, level1) {
  if (!geo || !geo.tree) return [];
  const keys = Object.keys(geo.tree);
  const n = geoNorm(level1);
  for (const k of keys) { if (geoNorm(k) === n) return geo.tree[k] || []; }
  const all = [];
  for (const k of keys) { const a = geo.tree[k]; if (Array.isArray(a)) all.push(...a); }
  return [...new Set(all)];
}
